package be.schaubroeck.lpb.rkm.rekenmotor.check;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import com.google.common.collect.ImmutableSet;

import java.util.Collection;
import java.util.List;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENMODUS_KEY;

public class VermijdenFiche25 {

    private static final Set<RekenBedragType> BB_OR_BVAST = ImmutableSet.of(RekenBedragType.BELASTBAAR,
            RekenBedragType.BEDRIJFSVOORHEFFING_ACHTERSTAL);

    private Rekenmodus rekenModus;
    private List<RekenHoofd> bestaanden;

    private void fillParam(RekenContext context) {
        this.rekenModus = context.getUnchecked(REKENMODUS_KEY);
        PersoonsDataManager persoonsDataManager = context.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        RekenTijd rekenTijd = context.getRekenTijd();
        this.bestaanden = persoonsDataManager.getBestaandeRekenResultaten(rekenTijd.beginDatum);
    }

    public boolean isUitzonderingOpDalendFiscaalJaar(RekenContext context) {
        fillParam(context);
        return rekenModus == Rekenmodus.VERMIJDEN_FICHE_25 && geenBbOfBvAchterstalInBestaande();
    }

    private boolean geenBbOfBvAchterstalInBestaande() {
        MoneyMap<RegimeBedragTypeKey> bbOfBvAchterstalMap = new HashMoneyMap<>();
        bestaanden.stream()
                .filter(this::fiscaalJaarIsVerschillendVanFysischJaar)
                .map(RekenHoofd::getRekenLijnen).flatMap(Collection::stream)
                .map(RekenLijn::getRekenBedragen).flatMap(Collection::stream)
                .filter(this::isBelastbaarOfBvAchterstal)
                .forEach(x -> bbOfBvAchterstalMap.addToMoney(new RegimeBedragTypeKey(x), x.getBedrag()));
        return bbOfBvAchterstalMap.values().stream().noneMatch(this::isBedragVerschillendVanNul);
    }

    private boolean isBedragVerschillendVanNul(Money bedrag) {
        return bedrag.signum() != 0;
    }

    private boolean fiscaalJaarIsVerschillendVanFysischJaar(RekenHoofd rekenHoofd) {
        return !rekenHoofd.getFiscaalJaar().equals(rekenHoofd.getBeginDatum().getYear());
    }

    private boolean isBelastbaarOfBvAchterstal(RekenBedrag rekenBedrag) {
        return BB_OR_BVAST.contains(rekenBedrag.getBedragType());
    }

}
